import{_ as a,o as l,c as i,al as o}from"./chunks/framework.L5dtSe-v.js";const d=JSON.parse('{"title":"OURMC MINECRAFT 服务器","description":"","frontmatter":{},"headers":[],"relativePath":"EULA.md","filePath":"EULA.md","lastUpdated":1774776398000}'),t={name:"EULA.md"};function n(e,r,s,p,h,g){return l(),i("div",null,[...r[0]||(r[0]=[o('<h1 id="ourmc-minecraft-服务器" tabindex="-1">OURMC MINECRAFT 服务器 <a class="header-anchor" href="#ourmc-minecraft-服务器" aria-label="Permalink to “OURMC MINECRAFT 服务器”">​</a></h1><h2 id="最终用户许可协议-eula" tabindex="-1">最终用户许可协议（EULA） <a class="header-anchor" href="#最终用户许可协议-eula" aria-label="Permalink to “最终用户许可协议（EULA）”">​</a></h2><p><strong>版本号：</strong> 2.4.0<br><strong>生效日期：</strong> 2026年03月20日</p><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to “前言”">​</a></h2><p>本协议由 OurMC 服务器管理团队（以下简称“运营方”）与所有访问、登录、使用 OurMC Minecraft 服务器及配套服务的用户（以下简称“用户”或“您”）共同签订。</p><p>您通过连接、登录或以任何方式使用本服务器，即视为已充分阅读、理解并同意本协议全部内容。</p><p>如您为未成年人，应遵守《未成年人网络保护条例》；如您未满14周岁，使用本服务前应取得监护人的明示同意。监护人应履行监护义务，引导未成年人健康、合理使用网络服务。</p><hr><h2 id="第一章-定义与解释" tabindex="-1">第一章 定义与解释 <a class="header-anchor" href="#第一章-定义与解释" aria-label="Permalink to “第一章 定义与解释”">​</a></h2><ol><li><p><strong>本服务器</strong><br> 指由 OurMC 运营团队搭建、运营并维护的 Minecraft 多人游戏服务器，包括所有子服、配套网站、社区平台、插件系统及周边衍生服务。</p></li><li><p><strong>用户内容</strong><br> 指用户在服务器内生成、上传、发布、传播的一切数据，包括但不限于建筑作品、聊天文本、物品命名、截图、录像、建筑存档、指令配置及其他创作内容。</p></li><li><p><strong>第三方资源</strong><br> 指非运营方原创，但经合法授权整合至服务器的模组（Mod）、插件（Plugin）、光影、材质包、音效、地图等资源。</p></li><li><p><strong>严重违规行为</strong><br> 包括但不限于：使用外挂/作弊客户端、利用游戏漏洞牟利、现实货币交易游戏道具/账号（RMT）、盗号、诈骗、恶意攻击服务器、传播违法信息、严重破坏游戏秩序等行为。</p></li></ol><hr><h2 id="第二章-许可授予与使用限制" tabindex="-1">第二章 许可授予与使用限制 <a class="header-anchor" href="#第二章-许可授予与使用限制" aria-label="Permalink to “第二章 许可授予与使用限制”">​</a></h2><ol><li><p><strong>有限使用许可</strong><br> 运营方授予用户非独占、不可转让、可撤销、非商业性的有限许可，仅限用户通过合法获得的 Minecraft 客户端登录并游玩本服务器。实际开放内容以服务器实时公告为准。</p></li><li><p><strong>禁止商业使用</strong><br> 未经运营方许可，用户不得将服务器内容、游戏画面、直播、录屏、建筑作品等用于任何直接或间接营利活动。<br> 因公益慈善需要进行募捐的，应提前向运营方提交方案并获得许可。</p></li><li><p><strong>禁止逆向工程与破解</strong><br> 用户不得对 Minecraft 客户端、服务器服务端、通信协议进行反编译、逆向分析、破解、篡改或二次分发，法律法规明确允许的除外。</p></li></ol><hr><h2 id="第三章-用户义务" tabindex="-1">第三章 用户义务 <a class="header-anchor" href="#第三章-用户义务" aria-label="Permalink to “第三章 用户义务”">​</a></h2><ol><li><p><strong>账户安全责任</strong><br> 用户应妥善保管账号与密码，对账号下一切行为承担全部责任。<br> 禁止账号共享、租借、售卖、交易，禁止利用漏洞批量注册虚假账号。因用户自身保管不当导致账号被盗、损失的，由用户自行承担。</p></li><li><p><strong>行为规范</strong><br> 用户承诺遵守以下规则：</p><ul><li>不得使用任何外挂、作弊模组、自动化脚本、透视（X-Ray）、加速等破坏公平性的工具；</li><li>不得发布、传播色情、暴力、恐怖、仇恨言论、政治敏感信息及违反国家法律法规与公序良俗的内容；</li><li>不得实施 DDoS、CC、假人攻击、恶意刷屏、滥用漏洞等危害服务器稳定或干扰他人游戏的行为；</li><li>不得冒充管理员、官方人员或其他玩家进行欺诈；</li><li>尊重他人知识产权，不得盗用、复刻他人原创建筑或作品并据为己有。</li></ul></li><li><p><strong>内容审查</strong><br> 运营方有权对用户聊天、建筑、物品命名、公告等内容进行审查，对违规内容可直接删除、屏蔽，并视情节进行处罚。</p></li><li><p><strong>玩家基本公约</strong></p><ul><li>禁止恶意破坏、损毁他人建筑与作品；</li><li>禁止游戏内“抄家”行为，包括盗取他人物品、货币、资源等虚拟财产；</li><li>禁止骚扰、欺凌、辱骂其他玩家，禁止恶意影响他人正常游戏体验。</li></ul></li></ol><hr><h2 id="第四章-知识产权" tabindex="-1">第四章 知识产权 <a class="header-anchor" href="#第四章-知识产权" aria-label="Permalink to “第四章 知识产权”">​</a></h2><ol><li><p><strong>运营方知识产权</strong><br> 服务器原创机制、定制插件、专属模组、自定义纹理、世界观设定、UI 设计、文档及品牌标识等知识产权归 OurMC 团队所有，受《中华人民共和国著作权法》等法律保护。</p></li><li><p><strong>第三方资源</strong><br> 服务器使用的第三方资源均遵循原作者授权协议。如发生侵权争议，运营方将依法处理，包括下架、删除侵权内容并配合维权。</p></li><li><p><strong>用户内容授权</strong><br> 用户在服务器内创作的内容，著作权仍归用户所有，但用户授予运营方全球范围内、非独占、永久、免费、不可撤销的使用权，包括展示、宣传、存档保存、适度改编等，用于服务器运营与推广。</p></li></ol><hr><h2 id="第五章-免责与责任限制" tabindex="-1">第五章 免责与责任限制 <a class="header-anchor" href="#第五章-免责与责任限制" aria-label="Permalink to “第五章 免责与责任限制”">​</a></h2><ol><li><p><strong>服务可用性</strong><br> 运营方不承诺服务器 24 小时不间断运行。因维护、更新、故障、不可抗力等原因导致的临时停机，无需提前逐一通知，运营方不承担由此产生的玩家损失赔偿责任。</p></li><li><p><strong>数据与存档风险</strong><br> 用户应自行备份重要游戏数据与作品。运营方不对因漏洞、硬件故障、攻击、版本更新等导致的数据丢失承担赔偿责任，但将在能力范围内尽力协助恢复。</p></li><li><p><strong>第三方链接与广告</strong><br> 服务器内出现的第三方网站、广告、外链等内容，由第三方独立负责。用户因访问、使用产生的纠纷与损失，运营方不承担责任。</p></li></ol><hr><h2 id="第六章-违约处理与协议终止" tabindex="-1">第六章 违约处理与协议终止 <a class="header-anchor" href="#第六章-违约处理与协议终止" aria-label="Permalink to “第六章 违约处理与协议终止”">​</a></h2><ol><li><p><strong>违规处罚</strong><br> 用户违反本协议时，运营方可独立判断并采取以下措施：<br> 警告、禁言、清空违规物品/货币、临时封禁、永久封禁账号或 IP。<br> 对涉嫌违法犯罪的严重违规行为，运营方将保留证据，并向 Mojang Studios 备案，同时移交司法机关处理。</p></li><li><p><strong>协议终止</strong></p><ul><li>用户可随时停止使用服务，已支付的捐赠/赞助费用不予退还。</li><li>运营方可因业务调整、政策变化、合规要求等原因终止服务，将至少提前 30 日在官网、官方社群公告。</li><li>协议终止后，本章知识产权、免责条款、法律适用等条款继续有效。</li></ul></li></ol><hr><h2 id="第七章-通用条款" tabindex="-1">第七章 通用条款 <a class="header-anchor" href="#第七章-通用条款" aria-label="Permalink to “第七章 通用条款”">​</a></h2><ol><li><p><strong>法律适用</strong><br> 本协议适用中华人民共和国大陆地区法律。因协议产生的争议，双方应友好协商解决；协商不成的，提交运营方所在地有管辖权的人民法院诉讼解决。</p></li><li><p><strong>条款效力</strong><br> 如本协议任何条款被认定为无效或不可执行，不影响其他条款的法律效力。</p></li><li><p><strong>协议修改权</strong><br> 运营方有权根据运营需要、合规要求修订本协议。修订后将在官网、QQ 群、QQ 频道公示，公示满 72 小时自动生效。用户继续使用服务器即视为接受更新后的协议。</p></li><li><p><strong>主体声明</strong><br> OurMC 服务器由 Minecraft 玩家社区、HIGHLIGHT Studio、OURMC TEAM 共同管理运营。<br> 本服务器与上海网之易吾世界网络科技有限公司无直接关联，独立运营，不受 Mojang Studios 及 Microsoft 直接管理。</p></li></ol><hr><h2 id="联系我们" tabindex="-1">联系我们 <a class="header-anchor" href="#联系我们" aria-label="Permalink to “联系我们”">​</a></h2><p>法律咨询、违规举报、意见反馈：<br><strong>邮箱：</strong> <a href="mailto:team@our-mc.cn" target="_blank" rel="noreferrer">team@our-mc.cn</a></p><p>运营方将在收到信息后 4 个休息日内予以回复。</p>',33)])])}const c=a(t,[["render",n]]);export{d as __pageData,c as default};
